+import Foundation
+
+public extension Date {
+    var relativeTime: String {
+        let seconds = Int(-timeIntervalSinceNow)
+
+        if seconds < 60 {
+            return "just now"
+        } else if seconds < 3600 {
+            return "\(seconds / 60)m ago"
+        } else if seconds < 86400 {
+            return "\(seconds / 3600)h ago"
+        } else {
+            return "\(seconds / 86400)d ago"
+        }
+    }
+}

